import{_ as e,c as i,o,a2 as a}from"./chunks/framework.DdOM6S6U.js";const g=JSON.parse('{"title":"API Guide","description":"","frontmatter":{"sidebarPos":9,"sidebarTitle":"API"},"headers":[],"relativePath":"system-reference/api.md","filePath":"system-reference/api.md","lastUpdated":null}'),r={name:"system-reference/api.md"},t=a(`<h1 id="api-guide" tabindex="-1">API Guide <a class="header-anchor" href="#api-guide" aria-label="Permalink to &quot;API Guide&quot;">​</a></h1><p>Common use cases and patterns for developers.</p><h2 id="adding-a-new-module" tabindex="-1">Adding a New Module <a class="header-anchor" href="#adding-a-new-module" aria-label="Permalink to &quot;Adding a New Module&quot;">​</a></h2><ol><li>Create <code>modules/MyModule/</code> with <code>module.json</code></li><li>Add <code>Config/</code>, <code>Database/Migrations/</code>, <code>Entities/</code>, <code>Http/Controllers/</code>, <code>Repositories/</code>, <code>Routes/</code></li><li>Enable via <code>modules_statuses.json</code> or <code>php artisan module:enable MyModule</code></li><li>Run <code>php artisan modularity:build</code> to rebuild Vue assets if the module adds frontend pages</li></ol><h2 id="adding-a-new-input-type" tabindex="-1">Adding a New Input Type <a class="header-anchor" href="#adding-a-new-input-type" aria-label="Permalink to &quot;Adding a New Input Type&quot;">​</a></h2><ol><li>Create component in <code>vue/src/js/components/inputs/</code> (e.g. <code>InputPrice.vue</code>)</li><li>Register in app bootstrap or a plugin:</li></ol><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { registerInputType } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@/components/inputs/registry&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">registerInputType</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;input-price&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;VInputPrice&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><ol start="3"><li>Use in schema: <code>{ myField: { type: &#39;input-price&#39;, ... } }</code></li></ol><p>See <a href="./hydrates#adding-a-new-input">Hydrates</a> for full flow (PHP Hydrate + Vue component).</p><h2 id="repository-pattern" tabindex="-1">Repository Pattern <a class="header-anchor" href="#repository-pattern" aria-label="Permalink to &quot;Repository Pattern&quot;">​</a></h2><ul><li>All data access goes through repositories</li><li>Use <code>$this-&gt;repository</code> in controllers (from PanelController)</li><li>Lifecycle: <code>prepareFieldsBeforeCreate</code> → <code>create</code> → <code>beforeSave</code> → <code>prepareFieldsBeforeSave</code> → <code>save</code> → <code>afterSave</code></li><li>See <a href="./repositories">Repositories</a> for full lifecycle</li></ul><h2 id="controller-flow" tabindex="-1">Controller Flow <a class="header-anchor" href="#controller-flow" aria-label="Permalink to &quot;Controller Flow&quot;">​</a></h2><ul><li><code>preload()</code> — runs before index/create/edit; calls <code>addWiths()</code>, <code>setupFormSchema()</code></li><li><code>setupFormSchema()</code> — hydrates form inputs via InputHydrator</li><li><code>index()</code> — <code>addWiths()</code>, <code>addIndexWiths()</code>, <code>respondToIndexAjax()</code> for AJAX, else <code>getIndexData()</code> → <code>renderIndex()</code></li><li><code>create()</code> / <code>edit()</code> — load form schema, pass to view/Inertia</li></ul><h2 id="finder" tabindex="-1">Finder <a class="header-anchor" href="#finder" aria-label="Permalink to &quot;Finder&quot;">​</a></h2><ul><li><code>Finder::getModel($table)</code> — resolve model class from table name (scans modules, then app/Models)</li><li><code>Finder::getRouteModel($routeName)</code> — resolve model from route name</li><li>Used by Module to resolve repository, model, controller</li></ul><h2 id="route-generation" tabindex="-1">Route Generation <a class="header-anchor" href="#route-generation" aria-label="Permalink to &quot;Route Generation&quot;">​</a></h2><p>Use <code>php artisan modularity:make:route</code> to scaffold routes, migrations, controllers, repositories from module config. See <a href="/guide/commands/Generators/make-route">make:route</a>.</p><h2 id="currency-provider" tabindex="-1">Currency Provider <a class="header-anchor" href="#currency-provider" aria-label="Permalink to &quot;Currency Provider&quot;">​</a></h2><p>When adding pricing without SystemPricing module:</p><ol><li>Implement <code>CurrencyProviderInterface</code></li><li>Register in config: <code>modularity.currency_provider</code> = YourProvider::class</li><li>Or bind in a service provider: <code>$app-&gt;singleton(CurrencyProviderInterface::class, YourProvider::class)</code></li></ol><h2 id="helpers-frontend" tabindex="-1">Helpers (Frontend) <a class="header-anchor" href="#helpers-frontend" aria-label="Permalink to &quot;Helpers (Frontend)&quot;">​</a></h2><p>Prefer imports over window globals:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { isObject, dataGet, isset } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@/utils/helpers&#39;</span></span></code></pre></div><h2 id="config-keys" tabindex="-1">Config Keys <a class="header-anchor" href="#config-keys" aria-label="Permalink to &quot;Config Keys&quot;">​</a></h2><ul><li><code>modularity.services.*</code> — service config (currency_exchange, etc.)</li><li><code>modularity.roles</code> — role definitions</li><li><code>modularity.traits</code> — entity traits</li><li><code>modularity.paths</code> — base paths</li></ul>`,25),s=[t];function d(l,n,c,p,h,u){return o(),i("div",null,s)}const f=e(r,[["render",d]]);export{g as __pageData,f as default};
